SELECT COUNT(score_id) AS total_quizzes, MAX(score) AS max_score
FROM mysql_scores
WHERE assessment_type = 'quiz';

SELECT student_id, score, language_version, score_date, MAX(score_category) AS max_score_category
FROM python_scores
GROUP BY student_id, score, language_version, score_date;

SELECT student_id, score
FROM python_scores
WHERE score >= 25;

SELECT score
FROM python_scores
WHERE student_id = 0;

SELECT MAX(score) AS max_score
FROM computational_thinking_scores
WHERE assessment_type = 'exam' AND score_category = 'final exam';

SELECT student_id, score, score_date
FROM computational_thinking_scores
WHERE assessment_type = 'quiz';

SELECT score
FROM python_scores
WHERE score_id = 1;
